// File: VirtualThreadDemo.java
// Requires Java 21+. Run: javac VirtualThreadDemo.java && java VirtualThreadDemo
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.time.Duration;

public class VirtualThreadDemo {
  public static void main(String[] args) throws Exception {
    // Simulate 1,000,000 tasks that each 'wait for I/O' by sleeping.
    // On platform threads this would need 1M OS threads — probably not possible.
    // On virtual threads, the JVM multiplexes them onto ~16 carriers.
    AtomicInteger done = new AtomicInteger();
    long t0 = System.currentTimeMillis();

    try (var exec = Executors.newVirtualThreadPerTaskExecutor()) {
      for (int i = 0; i < 1_000_000; i++) {
        exec.submit(() -> {
          try {
            Thread.sleep(Duration.ofSeconds(1));   // 'I/O wait'
            done.incrementAndGet();
          } catch (InterruptedException e) { }
        });
      }
    }   // close() waits for all tasks

    long elapsed = System.currentTimeMillis() - t0;
    System.out.println("Completed " + done.get() + " tasks in " + elapsed + " ms");

    // For comparison, try this with 1 million platform threads:
    // Executors.newFixedThreadPool(1_000_000)
    //   → OutOfMemoryError: unable to create new native thread.
    //
    // Virtual threads make thread-per-request the RIGHT answer again.
  }
}

// Typical output on a laptop:
//   Completed 1000000 tasks in 1450 ms
//
// One MILLION 'threads' that each waited 1 second — done in 1.5 sec total.
// Total memory used: ~1-2 GB. On platform threads, this would need ~1 TB.
